  async function run(options={}){
    const {rebuildInputs=true,awaitHeavy=false}=options;
    // Always invalidate the cache because filters or inputs may have changed.
    _invalidateScenarioCache();
    // Heavy data is prefetched on boot. Block on first explicit Run, or if caller asks.
    if((_hasRun||awaitHeavy)&&!_invLoaded)await loadHeavyData();
    // If we're in projections seed mode, make sure projections are ready before computing.
    if(isProjectionSeedMode()&&!_projLoaded)await loadProjectionData();
    _setCalculating(true);
    try{
      applyScopeFilters();
      if(_invLoaded)buildProductFamilies();else PRODUCT_FAMILIES=[];
      if(rebuildInputs){renderRevenuePlanInputs();renderAssumptionStrips();}
      // Always compute LAST_RESULT so toggles and tabs can read cached data after first Run.
      LAST_RESULT=selectedScenario();
      if(_hasRun){
        // Render every output section so tab switches are pure view changes; no re-calc required.
        renderWorkbenchKpis();renderKpiStrip();renderCalculationBasis();
        renderProjectionSeedSummary();renderPlanningSummary();
        renderTop();renderScenarioMatrix();renderMonthly();renderGapAndChannel();renderFamilies();
        _syncMetricActiveClasses();
      }else{
        renderCalculationBasis();renderProjectionSeedSummary();renderPlanningSummary();
        renderKpiStrip();renderTop()
      }
      renderStatus();
      const isRevenuePlan=getPlanMode()==="revenue_plan";
      if(el("planningInputs"))el("planningInputs").style.display=isRevenuePlan?"":"none";
      if(el("historicalAssumptionWrap"))el("historicalAssumptionWrap").style.display=isRevenuePlan?"none":"";
      if(el("projSeedSection"))el("projSeedSection").hidden=!isProjectionSeedMode();
      if(el("projWorkbenchSection"))el("projWorkbenchSection").hidden=true;
      _setDirty(false);
    }finally{
      _setCalculating(false);
    }
  }
  // Reflect current SUMMARY/MONTHLY/FAMILY state in DOM .active classes so user always sees an active choice.
  function _syncMetricActiveClasses(){
    document.querySelectorAll("[data-summary-metric]").forEach(b=>b.classList.toggle("active",b.getAttribute("data-summary-metric")===SUMMARY_METRIC));
    document.querySelectorAll("[data-monthly-metric]").forEach(b=>b.classList.toggle("active",b.getAttribute("data-monthly-metric")===MONTHLY_METRIC));
    document.querySelectorAll("[data-family-filter]").forEach(b=>b.classList.toggle("active",b.getAttribute("data-family-filter")===FAMILY_FILTER));
  }
